\begin{align}
\exp
\begin{pmatrix}
\lambda & 1\\
0 & \lambda
\end{pmatrix}
&= \exp(\lambda I + N)\\
&= \exp(\lambda I) \exp(N)\quad (\because \lambda IとNは可換)\\
&= (e^\lambda I) (I + N) \quad (\because N^2=O)\\
&=
\begin{pmatrix}
e^\lambda & e^\lambda\\
0 & e^\lambda
\end{pmatrix}
\end{align}

\begin{align}
\exp(A)^T
&= \exp(A^T) \quad (\because 転置の定理 (AB)^T = B^T A^T より、 (A^n)^T = (A^T)^n )\\
&= \exp(-A) \quad (\because Aが交代行列という仮定) \\
&= \exp(A)^{-1} \quad (\because \exp(A)\exp(-A) = \exp(A-A) = I より \exp(-A) = \exp(A)^{-1})
\end{align}
